/**
 * Safely reads the initially selected language from localStorage.
 * @returns {string}
 */
function getInitialLanguage() {
  try {
    const saved = String(localStorage.getItem(LANGUAGE_STORAGE_KEY) || 'es');
    return SUPPORTED_LANGUAGES.some((item) => item.code === saved) ? saved : 'es';
  } catch {
    return 'es';
  }
}

/**
 * Resolves a nested translation path from the current dictionary with Spanish fallback.
 * @param {string} language
 * @param {string} key
 * @returns {string}
 */
function getTranslationValue(language, key) {
  const segments = String(key || '').split('.');
  let current = TRANSLATIONS[language];
  let fallback = TRANSLATIONS.es;
  let english = TRANSLATIONS.en;

  for (const segment of segments) {
    current = current?.[segment];
    fallback = fallback?.[segment];
    english = english?.[segment];
  }

  if (language !== 'es') {
    if (typeof current === 'string' && typeof fallback === 'string' && current !== fallback) {
      return current;
    }

    if (typeof english === 'string' && typeof fallback === 'string' && english !== fallback) {
      return english;
    }
  }

  if (language === 'en') {
    if (typeof current === 'string' && typeof fallback === 'string' && current !== fallback) {
      return current;
    }

    return humanizeTranslationKey(key);
  }

  return typeof current === 'string' ? current : String(fallback || key);
}

/**
 * Replaces {variables} in translated templates.
 * @param {string} template
 * @param {Record<string, string | number>} variables
 * @returns {string}
 */
function interpolate(template, variables = {}) {
  return String(template).replace(/\{(\w+)\}/g, (_, key) => String(variables[key] ?? ''));
}

/**
 * Provides app-wide language state, translation helpers, and locale-aware formatters.
 * @param {{ children: import('react').ReactNode }} props
 */
export function LanguageProvider({ children }) {
  const [language, setLanguage] = useState(getInitialLanguage);

  useEffect(() => {
    const selected = SUPPORTED_LANGUAGES.find((item) => item.code === language) || SUPPORTED_LANGUAGES[0];
    document.documentElement.lang = selected.locale;
    try {
      localStorage.setItem(LANGUAGE_STORAGE_KEY, language);
    } catch {
      // Ignore persistence errors.
    }
  }, [language]);

  const value = useMemo(() => {
    const selected = SUPPORTED_LANGUAGES.find((item) => item.code === language) || SUPPORTED_LANGUAGES[0];

    return {
      language,
      locale: selected.locale,
      languages: SUPPORTED_LANGUAGES,
      setLanguage,
      t: (key, variables) => interpolate(getTranslationValue(language, key), variables),
      formatCurrency: (amount) => new Intl.NumberFormat(selected.locale, {
        style: 'currency',
        currency: 'EUR',
        minimumFractionDigits: 2,
      }).format(Number(amount) || 0),
      formatDateTime: (value, options) => new Intl.DateTimeFormat(selected.locale, options || {
        dateStyle: 'medium',
        timeStyle: 'short',
      }).format(new Date(value)),
      formatDateRange: (from, to, options) => {
        const formatter = new Intl.DateTimeFormat(selected.locale, options || { day: 'numeric', month: 'short' });
        return `${formatter.format(from)} - ${formatter.format(to)}`;
      },
      translateCategory: (value) => {
        const categoryValue = String(value);
        const translations = CATEGORY_TRANSLATIONS[categoryValue] || null;
        if (translations?.[language]) {
          return translations[language];
        }

        if (language === 'es') {
          return categoryValue;
        }

        if (translations?.en) {
          return translations.en;
        }

        const normalizedCategory = normalizeTextForLookup(categoryValue);
        const canonicalByAlias = {
          todos: 'all', all: 'all',
          general: 'general',
          electronica: 'electronics', electronics: 'electronics',
          deportes: 'sports', sports: 'sports', esports: 'sports',
          accesorios: 'accessories', accessories: 'accessories',
          hogar: 'home', fogar: 'home', llar: 'home', home: 'home',
          libros: 'books', llibres: 'books', books: 'books',
          cocina: 'kitchen', cuina: 'kitchen', cocinaa: 'kitchen', kitchen: 'kitchen',
          beleza: 'beauty', belleza: 'beauty', bellesa: 'beauty', beauty: 'beauty',
          mascotas: 'pets', pets: 'pets',
          jardin: 'garden', xardin: 'garden', jardi: 'garden', garden: 'garden',
          moda: 'fashion', fashion: 'fashion',
          juguetes: 'toys', xoguetes: 'toys', joguets: 'toys', toys: 'toys',
          oficina: 'office', office: 'office',
          arte: 'art', art: 'art',
          musica: 'music', music: 'music',
          salud: 'health', saude: 'health', salut: 'health', health: 'health',
          viajes: 'travel', viatges: 'travel', travel: 'travel',
          fotografia: 'photography', photography: 'photography',
        };

        const categoryLabels = {
          all: { en: 'All', ca: 'Tots', gl: 'Todos', val: 'Tots' },
          general: { en: 'General', ca: 'General', gl: 'Xeral', val: 'General' },
          electronics: { en: 'Electronics', ca: 'Electrònica', gl: 'Electrónica', val: 'Electrònica' },
          sports: { en: 'Sports', ca: 'Esports', gl: 'Deportes', val: 'Esports' },
          accessories: { en: 'Accessories', ca: 'Accessoris', gl: 'Accesorios', val: 'Accessoris' },
          home: { en: 'Home', ca: 'Llar', gl: 'Fogar', val: 'Llar' },
          books: { en: 'Books', ca: 'Llibres', gl: 'Libros', val: 'Llibres' },
          kitchen: { en: 'Kitchen', ca: 'Cuina', gl: 'Cociña', val: 'Cuina' },
          beauty: { en: 'Beauty', ca: 'Bellesa', gl: 'Beleza', val: 'Bellesa' },
          pets: { en: 'Pets', ca: 'Mascotes', gl: 'Mascotas', val: 'Mascotes' },
          garden: { en: 'Garden', ca: 'Jardí', gl: 'Xardín', val: 'Jardí' },
          fashion: { en: 'Fashion', ca: 'Moda', gl: 'Moda', val: 'Moda' },
          toys: { en: 'Toys', ca: 'Joguets', gl: 'Xoguetes', val: 'Joguets' },
          office: { en: 'Office', ca: 'Oficina', gl: 'Oficina', val: 'Oficina' },
          art: { en: 'Art', ca: 'Art', gl: 'Arte', val: 'Art' },
          music: { en: 'Music', ca: 'Música', gl: 'Música', val: 'Música' },
          health: { en: 'Health', ca: 'Salut', gl: 'Saúde', val: 'Salut' },
          travel: { en: 'Travel', ca: 'Viatges', gl: 'Viaxes', val: 'Viatges' },
          photography: { en: 'Photography', ca: 'Fotografia', gl: 'Fotografía', val: 'Fotografia' },
        };

        const canonicalKey = canonicalByAlias[normalizedCategory];
        const mapped = canonicalKey ? categoryLabels[canonicalKey] : null;
        if (mapped?.[language]) {
          return mapped[language];
        }

        return mapped?.en || (language === 'ca' || language === 'val' ? 'Categoria' : 'Category');
      },
      translateProductText: (value) => {
        const textValue = String(value);
        const translations = PRODUCT_TEXT_TRANSLATIONS[textValue] || null;
        if (translations?.[language]) {
          return translations[language];
        }

        if (language === 'es') {
          return textValue;
        }

        if (translations?.en) {
          return translations.en;
        }

        const rough = roughTranslateSpanishTextToEnglish(normalizeTextForLookup(textValue));
        if (looksSpanish(rough)) {
          if (language === 'ca' || language === 'val') {
            return textValue.length > 45 ? 'Descripció del producte' : 'Producte';
          }
          return textValue.length > 45 ? 'Product description' : 'Product';
        }

        return rough.replace(/\b\w/g, (match) => match.toUpperCase());
      },
    };
  }, [language]);

  return <LanguageContext.Provider value={value}>{children}</LanguageContext.Provider>;
}